Here are the public test cases for feature1_function_composition:
{
  "description": "Right-to-left composition of unary numeric transformers applied to a seed value; with no transformers the seed passes through unchanged, with one it is returned as-is, and the rightmost transformer runs first.",
  "cases": [
    {
      "input": {
        "command": "compose_functions",
        "functions": [
          "square",
          "double"
        ],
        "input": [
          5
        ]
      },
      "expected_output": "result=100\n"
    },
    {
      "input": {
        "command": "compose_functions",
        "functions": [
          "square"
        ],
        "input": [
          5
        ]
      },
      "expected_output": "result=25\n"
    },
    {
      "input": {
        "command": "compose_functions",
        "functions": [],
        "input": [
          3
        ]
      },
      "expected_output": "result=3\n"
    }
  ]
}

Here are the public test cases for feature2_1_resolve_display_name:
{
  "description": "Resolve a component's human-facing label: an explicit label wins, otherwise the declared type name is used, an unnamed inline component falls back to the literal 'Component', and a raw markup tag string is returned verbatim.",
  "cases": [
    {
      "input": {
        "command": "display_name",
        "component": {
          "kind": "class_named",
          "name": "SomeComponent"
        }
      },
      "expected_output": "name=\"SomeComponent\"\n"
    },
    {
      "input": {
        "command": "display_name",
        "component": {
          "kind": "anonymous"
        }
      },
      "expected_output": "name=\"Component\"\n"
    },
    {
      "input": {
        "command": "display_name",
        "component": {
          "kind": "dom",
          "name": "div"
        }
      },
      "expected_output": "name=\"div\"\n"
    }
  ]
}

