Here are the public test cases for feature3_7_flatten_props:
{
  "description": "Spread the fields of one or more object-valued properties up into the top-level property set; the original object properties are also retained alongside the flattened fields.",
  "cases": [
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "flatten",
            "keys": "state"
          }
        ],
        "props": {
          "pass": "through",
          "state": {
            "counter": 1
          }
        }
      },
      "expected_output": "counter=1\npass=\"through\"\nstate={\"counter\":1}\n"
    },
    {
      "input": {
        "command": "transform_props",
        "stages": [
          {
            "op": "flatten",
            "keys": [
              "a",
              "b"
            ]
          }
        ],
        "props": {
          "pass": "through",
          "a": {
            "z": 1
          },
          "b": {
            "y": 2
          }
        }
      },
      "expected_output": "a={\"z\":1}\nb={\"y\":2}\npass=\"through\"\ny=2\nz=1\n"
    }
  ]
}

