Here are the public test cases for feature4_1_stateful_value:
{
  "description": "Attach a named state value and an updater. The updater accepts either a replacement value or a function of the previous value. State starts from a fixed seed or from an incoming property. Output emits the state after the initial render and after each update.",
  "cases": [
    {
      "input": {
        "command": "stateful_value",
        "state_name": "counter",
        "updater_name": "updateCounter",
        "initial": 0,
        "props": {
          "pass": "through"
        },
        "updates": [
          {
            "add": 9
          },
          {
            "mul": 2
          },
          {
            "mul": 2
          }
        ]
      },
      "expected_output": "counter=0\ncounter=9\ncounter=18\ncounter=36\n"
    },
    {
      "input": {
        "command": "stateful_value",
        "state_name": "counter",
        "updater_name": "updateCounter",
        "initial": 0,
        "updates": [
          {
            "set": 18
          }
        ]
      },
      "expected_output": "counter=0\ncounter=18\n"
    },
    {
      "input": {
        "command": "stateful_value",
        "state_name": "counter",
        "updater_name": "updateCounter",
        "initial_from": "initialCounter",
        "props": {
          "initialCounter": 1
        },
        "updates": [
          {
            "mul": 3
          }
        ]
      },
      "expected_output": "counter=1\ncounter=3\n"
    }
  ]
}

