      "expected_output": "isBad=false\nname=\"Walter\"\n"
    },
    {
      "input": {
        "command": "branch_transform",
        "test_prop": "isBad",
        "when_true": {
          "merge": {
            "name": "Heisenberg"
          }
        },
        "when_false": {
          "merge": {
            "name": "Walter"
          }
        },
        "props": {
          "isBad": true
        }
      },
      "expected_output": "isBad=true\nname=\"Heisenberg\"\n"
    }
  ]
}

